option.value:
.artist-root {
    -fx-font-family: "Segoe UI", Arial, sans-serif;
    -fx-background-color: #eaf3ff;
}

.artist-navbar {
    -fx-background-color: white;
    -fx-border-color: #dfe4ea;
    -fx-border-width: 0 0 1 0;
}

.artist-search-field {
    -fx-background-color: #f7f9fc;
    -fx-border-color: #d6deea;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
}

.artist-icon-button {
    -fx-background-color: #eef2f8;
    -fx-border-color: #d7dde7;
    -fx-background-radius: 17;
    -fx-border-radius: 17;
    -fx-font-weight: 700;
}

.artist-avatar-menu {
    -fx-background-color: #edf2f8;
    -fx-border-color: #d7dde7;
    -fx-background-radius: 16;
    -fx-border-radius: 16;
    -fx-font-weight: 700;
}

.artist-scroll,
.artist-scroll > .viewport {
    -fx-background-color: transparent;
}

.page-root,
.collections-page {
    -fx-background-color: transparent;
}

.artist-left-column {
    -fx-pref-width: 860;
}

.artist-page-host {
    -fx-background-color: transparent;
}

.profile-card,
.artist-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #dee2e6;
    -fx-border-radius: 12;
    -fx-effect: dropshadow(gaussian, rgba(0,0,0,0.05), 8, 0, 0, 2);
}

.profile-cover {
    -fx-background-color: linear-gradient(to right, #733f31, #c67b52);
    -fx-background-radius: 12 12 0 0;
}

.cover-title {
    -fx-text-fill: rgba(255, 255, 255, 0.85);
    -fx-font-size: 20px;
    -fx-font-weight: 700;
}

.profile-avatar {
    -fx-background-color: #e5e9ef;
    -fx-background-radius: 44;
    -fx-border-color: white;
    -fx-border-width: 3;
    -fx-border-radius: 44;
}

.avatar-text {
    -fx-text-fill: #7a8596;
    -fx-font-size: 26px;
    -fx-font-weight: 700;
}

.profile-avatar-image {
    -fx-background-radius: 999;
    -fx-border-radius: 999;
}

.profile-name {
    -fx-font-size: 26px;
    -fx-font-weight: 700;
    -fx-text-fill: #1f2937;
}

.profile-meta,
.card-text,
.page-subtitle-small {
    -fx-text-fill: #6c757d;
    -fx-font-size: 13px;
}

.collections-toolbar {
    -fx-padding: 2 0 10 0;
}

.collections-search-wrap {
    -fx-background-color: #f7f9fc;
    -fx-border-color: #d8dfeb;
    -fx-border-width: 1;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
    -fx-padding: 0;
}

.collections-search-field {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-background-radius: 10;
    -fx-border-radius: 10;
    -fx-padding: 7 28 7 10;
    -fx-font-size: 13px;
}

.collections-search-icon {
    -fx-text-fill: #7c8da6;
    -fx-font-size: 12px;
    -fx-padding: 0 10 0 0;
}

.collections-add-button {
    -fx-background-color: #3f44d4;
    -fx-text-fill: white;
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-padding: 8 16;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
    -fx-min-width: 165;
    -fx-cursor: hand;
}

.collections-add-button:hover {
    -fx-background-color: #2f2da3;
}

.oeuvres-select {
    -fx-background-color: #f7f9fc;
    -fx-border-color: #d3dbe8;
    -fx-border-width: 1;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
    -fx-font-size: 12px;
}

.edit-profile-button {
    -fx-background-color: #f8d7da;
    -fx-text-fill: #842029;
    -fx-background-radius: 8;
    -fx-font-weight: 600;
}

.tab-nav {
    -fx-border-color: #e5e7eb transparent transparent transparent;
    -fx-border-width: 1 0 0 0;
}

.tab-nav-item {
    -fx-background-color: transparent;
    -fx-text-fill: #6c757d;
    -fx-padding: 8 16;
    -fx-cursor: hand;
    -fx-border-color: transparent transparent #dee2e6 transparent;
    -fx-border-width: 0 0 2 0;
}

.tab-nav-item.active {
    -fx-text-fill: #0d6efd;
    -fx-border-color: transparent transparent #0d6efd transparent;
}

.card-title {
    -fx-font-size: 30px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.page-title-small {
    -fx-font-size: 18px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.badge-primary,
.badge-success,
.badge-warning,
.badge-info,
.badge-danger {
    -fx-padding: 2 8;
    -fx-background-radius: 4;
    -fx-font-weight: 600;
}

.badge-primary {
    -fx-background-color: #cfe2ff;
    -fx-text-fill: #084298;
}

.badge-success {
    -fx-background-color: #d1e7dd;
    -fx-text-fill: #0f5132;
}

.badge-warning {
    -fx-background-color: #fff3cd;
    -fx-text-fill: #664d03;
}

.badge-info {
    -fx-background-color: #cff4fc;
    -fx-text-fill: #055160;
}

.badge-danger {
    -fx-background-color: #f8d7da;
    -fx-text-fill: #842029;
}

.card-label {
    -fx-text-fill: #6c757d;
    -fx-font-size: 13px;
    -fx-font-weight: 600;
}

.sidebar-avatar {
    -fx-background-color: #e5e9ef;
    -fx-background-radius: 999;
    -fx-border-color: white;
    -fx-border-radius: 999;
    -fx-border-width: 3;
}

.sidebar-avatar-symbol {
    -fx-font-size: 22px;
    -fx-text-fill: #7a8596;
}

.sidebar-avatar-image {
    -fx-background-radius: 999;
    -fx-border-radius: 999;
}

.artist-primary-button {
    -fx-background-color: #3d3bc2;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 8;
    -fx-cursor: hand;
}

.artist-primary-button:hover {
    -fx-background-color: #3432ad;
}

.artist-secondary-button {
    -fx-background-color: #f1f4f8;
    -fx-border-color: #ced6e0;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-text-fill: #2f3e52;
    -fx-font-weight: 600;
    -fx-cursor: hand;
}

.artist-danger-button {
    -fx-background-color: #ffe8ea;
    -fx-border-color: #f3b7be;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-text-fill: #a63038;
    -fx-font-weight: 700;
    -fx-cursor: hand;
}

.artist-form-root {
    -fx-background-color: #f8f9fb;
    -fx-min-width: 640;
}

.artist-form-field,
.artist-form-combo {
    -fx-background-color: #f6f7fb;
    -fx-border-color: #d7dce6;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 8 10 8 10;
}

.artist-form-date {
    -fx-background-color: #f6f7fb;
    -fx-border-color: #d7dce6;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
}

.artist-form-date .text-field {
    -fx-background-color: transparent;
    -fx-padding: 8 10 8 10;
}

.artist-form-combo .list-cell {
    -fx-background-color: transparent;
}

.artist-form-text-area {
    -fx-background-color: #f6f7fb;
    -fx-border-color: #d7dce6;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 8 10 8 10;
    -fx-background-insets: 0;
}

.artist-form-text-area .content {
    -fx-background-color: #f6f7fb;
    -fx-background-radius: 8;
}

.artist-form-error {
    -fx-text-fill: #c62828;
    -fx-font-size: 12px;
    -fx-font-weight: 600;
}

.artist-events-scroll,
.artist-events-scroll > .viewport {
    -fx-background-color: transparent;
}

.artist-events-list {
    -fx-background-color: transparent;
}

.artist-event-card {
    -fx-background-color: #fdfefe;
    -fx-border-color: #e4e9f0;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
}

.artist-event-image {
    -fx-background-color: #eef2f7;
    -fx-background-radius: 8;
}

.artist-event-title {
    -fx-font-size: 22px;
    -fx-font-weight: 700;
    -fx-text-fill: #1f2937;
}

.artist-event-meta {
    -fx-font-size: 13px;
    -fx-text-fill: #64748b;
}

.artist-event-desc {
    -fx-font-size: 14px;
    -fx-text-fill: #334155;
}

.artist-alert {
    -fx-background-color: #ffffff;
}

.artist-alert .header-panel {
    -fx-background-color: #f8f9fb;
    -fx-border-color: #d9dce3;
    -fx-border-width: 0 0 1 0;
}

.artist-alert .header-panel .label {
    -fx-text-fill: #2f3e52;
    -fx-font-weight: 700;
}

.artist-alert .content.label {
    -fx-text-fill: #3c4f67;
}

.collections-page {
    -fx-padding: 8;
}

.collections-body-card {
    -fx-background-color: white;
    -fx-border-color: #dee2e6;
    -fx-border-width: 1;
    -fx-background-radius: 10;
    -fx-border-radius: 10;
}

.collections-toolbar {
    -fx-padding: 2 0 8 0;
}

.collections-search-field {
    -fx-background-color: #f8f9fc;
    -fx-border-color: #d6deea;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 8 12;
    -fx-font-size: 14px;
}

.collections-search-button {
    -fx-background-color: #3f44d4;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 8;
    -fx-padding: 8 18;
    -fx-cursor: hand;
}

.collections-add-button {
    -fx-background-color: #3f44d4;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 8;
    -fx-padding: 8 16;
    -fx-min-width: 165;
    -fx-cursor: hand;
}

.collections-filter-combo {
    -fx-background-color: #f8f9fc;
    -fx-border-color: #d6deea;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 2 10;
    -fx-font-size: 14px;
}

.collections-filter-combo .arrow-button {
    -fx-background-color: transparent;
}

.collections-filter-combo .arrow {
    -fx-background-color: #64748b;
}

.collection-row {
    -fx-padding: 12 8;
    -fx-alignment: center-left;
}

.collection-item-box {
    -fx-background-color: #f8f9fc;
    -fx-border-color: #dfe4ea;
    -fx-border-width: 1;
    -fx-background-radius: 10;
    -fx-border-radius: 10;
    -fx-padding: 12;
}

.collection-item-box-drop-over {
    -fx-border-color: #3f44d4;
    -fx-background-color: #eef1ff;
}

.collection-content-divider {
    -fx-padding: 4 0 4 0;
}

.collection-content-divider .line {
    -fx-border-color: #e5e7eb;
    -fx-border-width: 1 0 0 0;
}

.collection-title {
    -fx-text-fill: #111827;
    -fx-font-size: 17px;
    -fx-font-weight: 700;
}

.collection-description {
    -fx-text-fill: #8b95a5;
    -fx-font-size: 12px;
    -fx-font-weight: 500;
}

.collection-actions {
    -fx-alignment: center-right;
}

.collection-menu-trigger {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-text-fill: #111827;
    -fx-font-size: 18px;
    -fx-font-weight: 700;
    -fx-padding: 2 10;
    -fx-cursor: hand;
}

.collection-menu-trigger:hover {
    -fx-background-color: #eef2f8;
    -fx-background-radius: 6;
}

.collection-expand-trigger {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-padding: 3 8;
    -fx-cursor: hand;
}

.collection-expand-trigger:hover {
    -fx-background-color: #eef2f8;
    -fx-background-radius: 6;
}

.collection-preview-box {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-padding: 8 0 0 0;
}

.collection-preview-row {
    -fx-alignment: center-left;
}

.collection-thumbnail-wrapper {
    -fx-border-color: #dfe4ea;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-cursor: hand;
}

.collection-preview-empty {
    -fx-font-size: 12px;
    -fx-text-fill: #8b95a5;
}

.collection-menu {
    -fx-background-color: white;
    -fx-background-radius: 8;
    -fx-border-color: #dfe4ea;
    -fx-border-radius: 8;
    -fx-padding: 4;
}

.collection-menu .menu-item {
    -fx-padding: 8 12;
}

.collection-menu .menu-item .label {
    -fx-text-fill: #4b5563;
    -fx-font-size: 13px;
    -fx-font-weight: 600;
}

.collection-menu .menu-item:focused {
    -fx-background-color: #eef2f8;
    -fx-background-radius: 6;
}

.collection-menu .menu-item.collection-menu-delete .label {
    -fx-text-fill: #dc3545;
}

.collections-list-card {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-background-radius: 0;
    -fx-border-radius: 0;
}

.oeuvres-feed-scroll,
.oeuvres-feed-scroll > .viewport {
    -fx-background-color: transparent;
}

.oeuvres-feed-list {
    -fx-padding: 4 2 8 2;
}

.oeuvre-post-card {
    -fx-background-color: #f8f9fc;
    -fx-border-color: #dfe4ea;
    -fx-border-width: 1;
    -fx-background-radius: 10;
    -fx-border-radius: 10;
    -fx-padding: 12;
}

.oeuvre-post-author {
    -fx-font-size: 15px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.oeuvre-post-avatar {
    -fx-min-width: 40;
    -fx-min-height: 40;
    -fx-max-width: 40;
    -fx-max-height: 40;
    -fx-background-color: #e8eef9;
    -fx-border-color: #d5def0;
    -fx-border-width: 1;
    -fx-background-radius: 20;
    -fx-border-radius: 20;
}

.oeuvre-post-avatar-text {
    -fx-font-size: 17px;
    -fx-font-weight: 700;
    -fx-text-fill: #4b5d8a;
}

.oeuvre-post-specialite {
    -fx-font-size: 12px;
    -fx-font-weight: 600;
    -fx-text-fill: #8b95a5;
}

.oeuvre-post-date {
    -fx-font-size: 12px;
    -fx-text-fill: #6b7280;
}

.oeuvre-post-title {
    -fx-font-size: 28px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.oeuvre-post-description {
    -fx-font-size: 13px;
    -fx-text-fill: #6b7280;
}

.oeuvre-post-tags {
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-text-fill: #3f44d4;
}

.oeuvre-post-image-wrapper {
    -fx-background-color: white;
    -fx-border-color: #e5e7eb;
    -fx-border-width: 1;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
    -fx-padding: 10;
    -fx-alignment: center;
}

.oeuvre-post-image-placeholder {
    -fx-text-fill: #9ca3af;
    -fx-font-size: 13px;
}

.oeuvre-post-stats {
    -fx-alignment: center-left;
}

.oeuvre-post-stat {
    -fx-font-size: 12px;
    -fx-text-fill: #6b7280;
    -fx-font-weight: 600;
}

.oeuvre-post-stat-chip {
    -fx-background-color: #eef2f8;
    -fx-background-radius: 999;
    -fx-padding: 4 10;
}

.oeuvre-post-stat-icon {
    -fx-fill: #6b7280;
}

.oeuvre-post-stat-count {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #4b5563;
}

.oeuvres-feed-scroll,
.oeuvres-feed-scroll > .viewport {
    -fx-background-color: transparent;
}

.oeuvres-feed-list {
    -fx-padding: 4 2 8 2;
    -fx-alignment: center;
}

.oeuvre-post-card {
    -fx-max-width: 760;
    -fx-padding: 12 14 12 14;
}

.oeuvre-post-image-wrapper {
    -fx-max-width: 720;
}

.oeuvres-feed-scroll,
.oeuvres-feed-scroll > .viewport {
    -fx-background-color: transparent;
}

.oeuvres-feed-list {
    -fx-padding: 4 2 8 2;
    -fx-alignment: center;
}

.oeuvre-post-card {
    -fx-max-width: 760;
    -fx-padding: 12 14 12 14;
}

.oeuvre-post-image-wrapper {
    -fx-max-width: 720;
}

.oeuvre-post-comments-box {
    -fx-background-color: #ffffff;
    -fx-border-color: #e5e7eb;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 10;
}

.oeuvre-post-comments-title {
    -fx-font-size: 13px;
    -fx-font-weight: 700;
    -fx-text-fill: #374151;
}

.oeuvre-post-comments-empty,
.oeuvre-post-comments-more {
    -fx-font-size: 12px;
    -fx-text-fill: #6b7280;
}

.oeuvre-post-comment-row {
    -fx-padding: 2 0 4 0;
}

.oeuvre-post-comment-avatar {
    -fx-min-width: 30;
    -fx-min-height: 30;
    -fx-max-width: 30;
    -fx-max-height: 30;
    -fx-background-color: #e8eef9;
    -fx-border-color: #d5def0;
    -fx-border-width: 1;
    -fx-background-radius: 15;
    -fx-border-radius: 15;
}

.oeuvre-post-comment-avatar-text {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #4b5d8a;
}

.oeuvre-post-comment-author {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.oeuvre-post-comment-date {
    -fx-font-size: 11px;
    -fx-text-fill: #9ca3af;
}

.oeuvre-post-comment-text {
    -fx-font-size: 12px;
    -fx-text-fill: #4b5563;
}

.collection-popup {
    -fx-background-color: white;
    -fx-background-radius: 10;
}

.popup-title {
    -fx-font-size: 30px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.popup-field-label {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-text-fill: #6b7280;
}

.popup-input {
    -fx-background-color: #f8f9fc;
    -fx-border-color: #d6deea;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
}

.popup-input-valid {
    -fx-border-color: #16a34a;
    -fx-background-color: #f0fdf4;
}

.popup-input-invalid {
    -fx-border-color: #dc2626;
    -fx-background-color: #fef2f2;
}

.popup-error {
    -fx-text-fill: #dc2626;
    -fx-font-size: 12px;
    -fx-font-weight: 600;
}

.popup-counter {
    -fx-text-fill: #6b7280;
    -fx-font-size: 12px;
    -fx-font-weight: 600;
}

.popup-counter-limit {
    -fx-text-fill: #dc2626;
}

.popup-close-button {
    -fx-background-color: #111827;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 8;
    -fx-padding: 8 14;
}

.popup-confirm-button {
    -fx-background-color: #3f44d4;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 8;
    -fx-padding: 8 14;
}

.artist-root.dark-mode {
    -fx-background-color: #151c2d;
}

.artist-root.dark-mode .artist-card,
.artist-root.dark-mode .profile-card,
.artist-root.dark-mode .artist-navbar {
    -fx-background-color: #1f2a40;
    -fx-border-color: #2f3b57;
}

.artist-root.dark-mode .profile-name,
.artist-root.dark-mode .card-title,
.artist-root.dark-mode .page-title-small {
    -fx-text-fill: #edf2ff;
}

.artist-root.dark-mode .profile-meta,
.artist-root.dark-mode .card-text,
.artist-root.dark-mode .page-subtitle-small,
.artist-root.dark-mode .tab-nav-item {
    -fx-text-fill: #b7c4dc;
}

.artist-root.dark-mode .collections-body-card {
    -fx-background-color: #1f2a40;
    -fx-border-color: #2f3b57;
}

.artist-root.dark-mode .collections-search-field {
    -fx-background-color: #2a3551;
    -fx-border-color: #43506f;
    -fx-text-fill: #edf2ff;
    -fx-prompt-text-fill: #b7c4dc;
}

.artist-root.dark-mode .collections-add-button {
    -fx-background-color: #2d3956;
